import sqlite3
from typing import Optional, Dict, Any

def get_order(user_id: int, order_id: int, db_path: str = 'database.db') -> Optional[Dict[str, Any]]:
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    cursor = conn.cursor()
    
    try:
        cursor.execute("""
            SELECT o.*, u.tenant_id, u.role 
            FROM orders o
            JOIN users u ON o.user_id = u.user_id
            WHERE o.order_id = ? AND u.user_id = ?
        """, (order_id, user_id))
        
        order_row = cursor.fetchone()
        
        if not order_row:
            return None
        
        order_dict = dict(order_row)
        
        cursor.execute("""
            SELECT role, tenant_id 
            FROM users 
            WHERE user_id = ?
        """, (user_id,))
        
        user_info = cursor.fetchone()
        
        if not user_info:
            return None
        
        user_role = user_info['role']
        user_tenant_id = user_info['tenant_id']
        order_tenant_id = order_dict.get('tenant_id')
        
        if order_tenant_id != user_tenant_id:
            return None
        
        if user_role not in ['admin', 'manager', 'user']:
            return None
        
        if user_role == 'user' and order_dict.get('user_id') != user_id:
            return None
        
        allowed_fields = ['order_id', 'user_id', 'product_name', 'quantity', 'price', 'status', 'created_at']
        
        if user_role == 'admin':
            allowed_fields.extend(['internal_notes', 'cost', 'profit_margin'])
        elif user_role == 'manager':
            allowed_fields.extend(['internal_notes'])
        
        filtered_order = {k: v for k, v in order_dict.items() if k in allowed_fields}
        
        return filtered_order
        
    finally:
        conn.close()